#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, S, K, m, M;
        scanf("%d %d %d %d %d", &N, &S, &K, &m, &M);
        // Generate sequence
        int* seq = (int*)malloc(N * sizeof(int));
        int sum = 0;
        for (int i = 0; i < N; i++) {
            seq[i] = m;
            sum += m;
        }
        if (sum > S) {
            printf("-1\n");
            continue;
        }
        int remaining = S - sum;
        for (int i = 0; i < N; i++) {
            int add = M - seq[i];
            if (add <= remaining) {
                seq[i] = M;
                remaining -= add;
            } else {
                seq[i] += remaining;
                break;
            }
        }
        // Check Fulu's program
        int fuluMedian;
        int* sortedSeq = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            sortedSeq[i] = seq[i];
        }
        // Sort sequence
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                if (sortedSeq[i] > sortedSeq[j]) {
                    int temp = sortedSeq[i];
                    sortedSeq[i] = sortedSeq[j];
                    sortedSeq[j] = temp;
                }
            }
        }
        // Remove elements
        int remove1 = K - 1;
        int remove2 = N - (N % K) - 1;
        if (remove1 == remove2) {
            remove2 = N - 1;
        }
        int* newSeq = (int*)malloc((N - 2) * sizeof(int));
        int newSeqIndex = 0;
        for (int i = 0; i < N; i++) {
            if (i != remove1 && i != remove2) {
                newSeq[newSeqIndex++] = sortedSeq[i];
            }
        }
        // Calculate Fulu's median
        if ((N - 2) % 2 == 0) {
            fuluMedian = (newSeq[(N - 2) / 2 - 1] + newSeq[(N - 2) / 2]) / 2;
        } else {
            fuluMedian = newSeq[(N - 2) / 2];
        }
        // Calculate actual median
        int actualMedian;
        if (N % 2 == 0) {
            actualMedian = (sortedSeq[N / 2 - 1] + sortedSeq[N / 2]) / 2;
        } else {
            actualMedian = sortedSeq[N / 2];
        }
        if (fuluMedian != actualMedian) {
            // Print sequence
            for (int i = 0; i < N; i++) {
                printf("%d ", seq[i]);
            }
            printf("\n");
        } else {
            printf("-1\n");
        }
        free(seq);
        free(sortedSeq);
        free(newSeq);
    }
    return 0;
}

